#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeMlsClient: FfiConverter {

    typealias FfiType = UnsafeMutableRawPointer
    typealias SwiftType = MlsClient

    public static func lift(_ pointer: UnsafeMutableRawPointer) throws -> MlsClient {
        return MlsClient(unsafeFromRawPointer: pointer)
    }

    public static func lower(_ value: MlsClient) -> UnsafeMutableRawPointer {
        return value.uniffiClonePointer()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> MlsClient {
        let v: UInt64 = try readInt(&buf)
        // The Rust code won't compile if a pointer won't fit in a UInt64.
        // We have to go via `UInt` because that's the thing that's the size of a pointer.
        let ptr = UnsafeMutableRawPointer(bitPattern: UInt(truncatingIfNeeded: v))
        if (ptr == nil) {
            throw UniffiInternalError.unexpectedNullPointer
        }
        return try lift(ptr!)
    }

    public static func write(_ value: MlsClient, into buf: inout [UInt8]) {
        // This fiddling is because `Int` is the thing that's the same size as a pointer.
        // The Rust code won't compile if a pointer won't fit in a `UInt64`.
        writeInt(&buf, UInt64(bitPattern: Int64(Int(bitPattern: lower(value)))))
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeMlsClient_lift(_ pointer: UnsafeMutableRawPointer) throws -> MlsClient {
    return try FfiConverterTypeMlsClient.lift(pointer)
}

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeMlsClient_lower(_ value: MlsClient) -> UnsafeMutableRawPointer {
    return FfiConverterTypeMlsClient.lower(value)
}




/**
 * Commit (fan out to existing members) + welcome (deliver to the new member). Both opaque.
 */
public struct AddOutcome {
    public var commit: Data
    public var welcome: Data

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(commit: Data, welcome: Data) {
        self.commit = commit
        self.welcome = welcome
    }
}

#if compiler(>=6)
extension AddOutcome: Sendable {}
#endif


extension AddOutcome: Equatable, Hashable {
    public static func ==(lhs: AddOutcome, rhs: AddOutcome) -> Bool {
        if lhs.commit != rhs.commit {
            return false
        }
        if lhs.welcome != rhs.welcome {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(commit)
        hasher.combine(welcome)
    }
}



#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeAddOutcome: FfiConverterRustBuffer {
    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> AddOutcome {
        return
            try AddOutcome(
                commit: FfiConverterData.read(from: &buf), 
                welcome: FfiConverterData.read(from: &buf)
        )
    }

    public static func write(_ value: AddOutcome, into buf: inout [UInt8]) {
        FfiConverterData.write(value.commit, into: &buf)
        FfiConverterData.write(value.welcome, into: &buf)
    }
}


#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public func FfiConverterTypeAddOutcome_lift(_ buf: RustBuffer) throws -> AddOutcome {
