         * placeholder / tombstone driven by [`MlsClient::secret_phase`], never the body.
         */secretId: Data?) {
        self.localId = localId
        self.direction = direction
        self.plaintext = plaintext
        self.envelopeId = envelopeId
        self.secretId = secretId
